query listProducts_Shopping($size: PositiveInt!, $isSingleCategory: Boolean!, $offset: Int, $sorting: [SortOption!], $customSorted: Boolean = false, $filtering: ItemFilteringInputType, $isGeoLocated: Boolean = false) {
  items(filtering: $filtering) {
    total
    recommendations {
      keywords: products
      __typename
    }
    results(
      size: $size
      buckets: [{sorting: $sorting, customSorted: $customSorted, offset: $offset}]
    ) {
      ...extendedItemFragment
      __typename
    }
    aggregations {
      availableStock @include(if: $isGeoLocated) {
        ...availabilityStockAggregation
        __typename
      }
      sellerCondition(size: $size) {
        cardinality
        values {
          count
          filtered
          condition
          __typename
        }
        __typename
      }
      collections(aggregable: true) {
        values {
          ...collectionAggregationFragment
          __typename
        }
        __typename
      }
      installments {
        values {
          ...collectionAggregationFragment
          __typename
        }
        __typename
      }
      categories(market: "fravega", flattened: $isSingleCategory) {
        ...categoryAggregationFragment
        children {
          ...categoryAggregationFragment
          __typename
        }
        __typename
      }
      attributes {
        ...attributeAggregationFragment
        __typename
      }
      salePrice {
        ...rangedSalePriceAggregationFragment
        __typename
      }
      brands {
        cardinality
        values(size: 6, sorting: FREQUENCY) {
          ...brandAggregationFragment
          __typename
        }
        __typename
      }
      __typename
    }
    listUniqueId
    __typename
  }
}

fragment extendedItemFragment on ExtendedItem {
  sellers {
    commercialName
    __typename
  }
  stockLabels
  id
  title
  katalogCategoryId
  brand {
    id
    name
    __typename
  }
  skus {
    results {
      code
      categorization(market: "fravega") {
        name
        slug
        __typename
      }
      resolvedBidId
      sponsored
      campaignId
      pricing(channel: "fravega-ecommerce") {
        channel
        listPrice
        salePrice
        discount
        __typename
      }
      netPricing: pricing(channel: "net-price") {
        channel
        listPrice
        salePrice
        discount
        __typename
      }
      __typename
    }
    __typename
  }
  gtin {
    __typename
    ... on EAN {
      number
      __typename
    }
  }
  id
  images
  collections(onlyThoseWithCockade: true) {
    cardinality
    values {
      id
      name
      slug
      count
      cockade(tag: "listing") {
        position
        image
        __typename
      }
      __typename
    }
    __typename
  }
  installments {
    cardinality
    values {
      id
      name
      slug
      count
      cockade(tag: "listing") {
        position
        image
        __typename
      }
      __typename
    }
    __typename
  }
  listPrice {
    amounts {
      min
      max
      __typename
    }
    __typename
  }
  salePrice {
    amounts {
      min
      max
      __typename
    }
    discounts {
      min
      max
      __typename
    }
    __typename
  }
  slug
  __typename
}

fragment availabilityStockAggregation on AvailabilityStockAggregation {
  deliveryTerms {
    value
    count
    __typename
  }
  types {
    value
    count
    __typename
  }
  costs {
    value
    count
    __typename
  }
  __typename
}

fragment collectionAggregationFragment on CollectionAggregation {
  id
  name
  count
  slug
  filtered
  __typename
}

fragment categoryAggregationFragment on CategoryAggregation {
  name
  slug
  count
  path {
    id
    name
    slug
    __typename
  }
  children {
    name
    slug
    count
    path {
      id
      name
      slug
      __typename
    }
    __typename
  }
  __typename
}

fragment attributeAggregationFragment on AttributeAggregation {
  name
  slug
  tags
  measureUnit {
    name
    symbol
    __typename
  }
  values(size: 20) {
    type
    value
    slug
    count
    seo
    filtered
    __typename
  }
  ranges {
    from
    to
    count
    value
    slug
    seo
    filtered {
      from
      to
      value
      slug
      seo
      __typename
    }
    __typename
  }
  __typename
}

fragment rangedSalePriceAggregationFragment on RangedSalePriceAggregation {
  amounts {
    ranges(size: 3) {
      from
      to
      count
      value
      slug
      __typename
    }
    min
    max
    __typename
  }
  discounts {
    ranges(interval: 10) {
      from
      count
      value
      slug
      __typename
    }
    __typename
  }
  __typename
}

fragment brandAggregationFragment on BrandAggregation {
  name
  count
  slug
  image
  filtered
  __typename
}
